BEGIN

  IF AD_isTriggerEnabled() = 'N' THEN 
    IF DELETING THEN 
      RETURN OLD; 
    ELSE 
      RETURN NEW; 
    END IF;
  END IF;

  IF UPDATING AND :OLD.Finished IS DISTINCT FROM :NEW.Finished THEN
    :NEW.em_sscces_nonconformity_closed := :NEW.Finished;
  END IF;

  IF DELETING THEN 
    RETURN OLD; 
  ELSE 
    RETURN NEW; 
  END IF;
END SSCCES_NC_CLOSE_TRG_FUNC
